    public void update()
    {
        SalesTable orig = this.orig();

        next update();

        if(this.UBSProjectDim != orig.UBSProjectDim)
        {
            ttsbegin;
            this.updateHeaderProjectDimension(this.UBSProjectDim);
            this.update();
            ttscommit;

            this.updateLinesProjectDimension();
        }
    }

    public void updateHeaderProjectDimension(RecId _UBSProjectDim)
    {
        DimensionAttributeValue dimAttrValue = DimensionAttributeValue::find(_UBSProjectDim);

        if(dimAttrValue)
        {
            DimensionAttributeValueSetStorage storage = DimensionAttributeValueSetStorage::find(this.defaultDimension);
            storage.addItem(dimAttrValue);
            this.defaultDimension = storage.save();

            DimensionAttrValueLedgerOverride override               = DimensionAttrValueLedgerOverride::findByDimensionAttrValueLedgerOverride(dimAttrValue.RecId,
                                                                                                                                                   Ledger::current());
            UBSInventSiteCrossCompany        inventSiteCrossCompany = UBSInventSiteCrossCompany::findByRecId(override.UBSInventSiteCCRecId);
                
            this.setInventSiteId(inventSiteCrossCompany.SiteId);
            this.DeliveryPostalAddress = LogisticsPostalAddress::findByLocation(InventSite::getLocationFromRole(InventSite::find(inventSiteCrossCompany.SiteId).RecId, LogisticsLocationRoleType::Delivery)).RecId;

        }
    }

    public void updateLinesProjectDimension()
    {
        SalesLine                           SalesLine;
        DimensionAttributeValue             dimAttrValue = DimensionAttributeValue::find(this.UBSProjectDim);
        
        ttsbegin;
        while select forupdate SalesLine
            where SalesLine.SalesId == this.SalesId
        {
            DimensionAttributeValueSetStorage   storage = DimensionAttributeValueSetStorage::find(SalesLine.defaultDimension);
        
            if(dimAttrValue)
            {
                storage.addItem(dimAttrValue);
                SalesLine.defaultDimension = storage.save();

                DimensionAttrValueLedgerOverride    override                = DimensionAttrValueLedgerOverride::findByDimensionAttrValueLedgerOverride(dimAttrValue.RecId,
                                                                                                                                                       Ledger::current());
                UBSInventSiteCrossCompany           inventSiteCrossCompany  = UBSInventSiteCrossCompany::findByRecId(override.UBSInventSiteCCRecId);
                InventDim                           inventDim               = SalesLine.inventDim(true);
                
                inventDim.InventSiteId = inventSiteCrossCompany.SiteId;
                inventDim.update();

                SalesLine.modifyInventDim(inventDim,fieldNum(InventDim, InventSiteId), false);
                SalesLine.DeliveryPostalAddress = LogisticsPostalAddress::findByLocation(InventSite::getLocationFromRole(InventSite::find(inventSiteCrossCompany.SiteId).RecId, LogisticsLocationRoleType::Delivery)).RecId;

                SalesLine.update();
            }
        }
        ttscommit;
    }
